function s(s){return String(s??"").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;")}function n(n,a={},i="study-basis-panel"){if("undefined"==typeof document)return;const l=document.getElementById(i);if(!l)return;const{standard:t="",clause:e="",formulas:d=[],assumptions:u=[],limitations:c=[],benchmarkId:r=""}=a,o=d.length?`<div class="study-basis__section">\n        <h4>Key Formulas</h4>\n        <ul class="study-basis__list study-basis__list--code">\n          ${d.map(n=>`<li><code>${s(n)}</code></li>`).join("\n          ")}\n        </ul>\n       </div>`:"",_=u.length?`<div class="study-basis__section">\n        <h4>Assumptions</h4>\n        <ul class="study-basis__list">\n          ${u.map(n=>`<li>${s(n)}</li>`).join("\n          ")}\n        </ul>\n       </div>`:"",p=c.length?`<div class="study-basis__section">\n        <h4>Known Limitations</h4>\n        <ul class="study-basis__list study-basis__list--warn">\n          ${c.map(n=>`<li>${s(n)}</li>`).join("\n          ")}\n        </ul>\n       </div>`:"",m=r?`<p class="study-basis__benchmark-link">\n         <a href="validation.html#${s(r)}">View benchmark case &rarr;</a>\n       </p>`:"",y=`${i}-heading`;l.innerHTML=`\n    <details class="study-basis-panel" aria-labelledby="${y}">\n      <summary class="study-basis-panel__summary" id="${y}">\n        <span class="study-basis-panel__title">Calculation Basis</span>\n        <span class="study-basis-panel__standard">${s(t)}${e?` — ${s(e)}`:""}</span>\n      </summary>\n      <div class="study-basis-panel__body">\n        ${o}\n        ${_}\n        ${p}\n        ${m}\n      </div>\n    </details>`}export{n as i};
